package com.example.saml.saml;

import net.shibboleth.shared.codec.Base64Support;
import net.shibboleth.shared.xml.SerializeSupport;
import org.opensaml.core.xml.XMLObject;
import org.opensaml.core.xml.config.XMLObjectProviderRegistrySupport;
import org.opensaml.core.xml.io.Unmarshaller;
import org.opensaml.core.xml.io.UnmarshallingException;
import org.opensaml.saml.saml2.core.*;
import org.opensaml.security.x509.X509Credential;
import org.opensaml.xmlsec.signature.Signature;
import org.opensaml.xmlsec.signature.support.SignatureException;
import org.opensaml.xmlsec.signature.support.SignatureValidator;
import org.w3c.dom.Document;
import org.w3c.dom.Element;

import javax.xml.parsers.DocumentBuilderFactory;
import java.io.ByteArrayInputStream;
import java.nio.charset.StandardCharsets;
import java.time.Duration;
import java.time.Instant;
import java.util.*;

public class SamlValidator {

    private final SamlProperties props;
    private final X509Credential idpSigningCredential;

    public SamlValidator(SamlProperties props) {
        this.props = props;
        if (props.getIdp().getSigningCertPem() == null || props.getIdp().getSigningCertPem().isBlank()) {
            throw new IllegalStateException("Missing saml.idp.signingCertPem");
        }
        this.idpSigningCredential = SamlCryptoUtils.credentialFromPem(null, props.getIdp().getSigningCertPem());
    }

    public record AssertionResult(String nameId, String sessionIndex, Map<String, List<String>> attributes) {}

    public AssertionResult validateAndExtract(String base64SamlResponse) {
        if (base64SamlResponse == null || base64SamlResponse.isBlank()) {
            throw new IllegalArgumentException("Missing SAMLResponse");
        }

        byte[] decoded = Base64Support.decode(base64SamlResponse);
        Response response = (Response) unmarshall(decoded);

        validateResponseBasics(response);

        if (props.getCrypto().isWantMessagesSigned()) {
            validateSignature(response.getSignature());
        }

        Assertion assertion = extractAssertion(response);
        if (props.getCrypto().isWantAssertionsSigned()) {
            validateSignature(assertion.getSignature());
        }

        validateAssertionConditions(assertion);

        String nameId = assertion.getSubject() != null && assertion.getSubject().getNameID() != null
                ? assertion.getSubject().getNameID().getValue()
                : null;

        String sessionIndex = null;
        if (assertion.getAuthnStatements() != null && !assertion.getAuthnStatements().isEmpty()) {
            sessionIndex = assertion.getAuthnStatements().get(0).getSessionIndex();
        }

        Map<String, List<String>> attrs = extractAttributes(assertion);

        return new AssertionResult(nameId, sessionIndex, attrs);
    }

    private void validateResponseBasics(Response response) {
        if (response.getIssueInstant() == null) {
            throw new IllegalStateException("Missing IssueInstant");
        }

        Instant now = Instant.now();
        int maxAge = props.getCrypto().getMaxIssueInstantAgeSeconds();
        int skew = props.getCrypto().getClockSkewSeconds();

        Instant earliest = now.minus(Duration.ofSeconds(maxAge + skew));
        Instant latest = now.plus(Duration.ofSeconds(skew));

        Instant ii = response.getIssueInstant();
        if (ii.isBefore(earliest) || ii.isAfter(latest)) {
            throw new IllegalStateException("Response IssueInstant outside allowed window");
        }

        if (response.getStatus() == null || response.getStatus().getStatusCode() == null) {
            throw new IllegalStateException("Missing Status");
        }
        String code = response.getStatus().getStatusCode().getValue();
        if (!StatusCode.SUCCESS.equals(code)) {
            throw new IllegalStateException("SAML response not success: " + code);
        }
    }

    private Assertion extractAssertion(Response response) {
        if (response.getAssertions() != null && !response.getAssertions().isEmpty()) {
            return response.getAssertions().get(0);
        }
        throw new IllegalStateException("No Assertion found (EncryptedAssertion not supported in this minimal sample)");
    }

    private void validateAssertionConditions(Assertion assertion) {
        Conditions cond = assertion.getConditions();
        if (cond == null) return;

        Instant now = Instant.now();
        int skew = props.getCrypto().getClockSkewSeconds();

        if (cond.getNotBefore() != null && now.plusSeconds(skew).isBefore(cond.getNotBefore())) {
            throw new IllegalStateException("Assertion not yet valid");
        }
        if (cond.getNotOnOrAfter() != null && now.minusSeconds(skew).isAfter(cond.getNotOnOrAfter())) {
            throw new IllegalStateException("Assertion expired");
        }
    }

    private void validateSignature(Signature sig) {
        if (sig == null) {
            throw new IllegalStateException("Missing Signature");
        }
        try {
            SignatureValidator.validate(sig, idpSigningCredential);
        } catch (SignatureException e) {
            throw new IllegalStateException("Signature validation failed", e);
        }
    }

    private Map<String, List<String>> extractAttributes(Assertion assertion) {
        Map<String, List<String>> attrs = new LinkedHashMap<>();
        if (assertion.getAttributeStatements() == null) return attrs;

        for (AttributeStatement st : assertion.getAttributeStatements()) {
            for (Attribute a : st.getAttributes()) {
                String name = a.getName();
                List<String> values = new ArrayList<>();
                for (XMLObject v : a.getAttributeValues()) {
                    String text = v.getDOM() != null ? v.getDOM().getTextContent() : SerializeSupport.nodeToString(v.getDOM());
                    if (text != null) values.add(text.trim());
                }
                attrs.put(name, values);
            }
        }
        return attrs;
    }

    private XMLObject unmarshall(byte[] xmlBytes) {
        try {
            DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
            dbf.setNamespaceAware(true);
            dbf.setExpandEntityReferences(false);
            dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
            dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);

            Document doc = dbf.newDocumentBuilder().parse(new ByteArrayInputStream(xmlBytes));
            Element element = doc.getDocumentElement();

            Unmarshaller unmarshaller = XMLObjectProviderRegistrySupport.getUnmarshallerFactory().getUnmarshaller(element);
            if (unmarshaller == null) {
                throw new IllegalStateException("No unmarshaller for " + element.getNodeName());
            }
            return unmarshaller.unmarshall(element);
        } catch (UnmarshallingException e) {
            throw new IllegalStateException("Unmarshal failed", e);
        } catch (Exception e) {
            throw new IllegalStateException("Parse failed", e);
        }
    }
}

