import java.security.PrivateKey;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.security.spec.PKCS8EncodedKeySpec;

public final class SamlCryptoUtils {

    private SamlCryptoUtils() {}

    public static X509Credential credentialFromPem(String privateKeyPem, String certPem) {
        X509Certificate cert = parseX509Cert(certPem);
        if (privateKeyPem == null || privateKeyPem.isBlank()) {
            BasicX509Credential cred = new BasicX509Credential(cert);
            return cred;
        }
        PrivateKey key = parsePrivateKey(privateKeyPem);
        BasicX509Credential cred = new BasicX509Credential(cert, key);
        return cred;
    }

    public static BasicCredential basicCredential(PrivateKey privateKey) {
        return new BasicCredential(privateKey);
    }

    private static X509Certificate parseX509Cert(String pem) {
        try {
            String cleaned = pem.replace("-----BEGIN CERTIFICATE-----", "")
                    .replace("-----END CERTIFICATE-----", "")
                    .replaceAll("\\s", "");
            byte[] der = Base64.decodeBase64(cleaned);
            CertificateFactory cf = CertificateFactory.getInstance("X.509");
            return (X509Certificate) cf.generateCertificate(new ByteArrayInputStream(der));
        } catch (Exception e) {
            throw new IllegalStateException("Failed to parse X509 cert PEM", e);
        }
    }

    private static PrivateKey parsePrivateKey(String pem) {
        try {
            String cleaned = pem
                    .replace("-----BEGIN PRIVATE KEY-----", "")
                    .replace("-----END PRIVATE KEY-----", "")
                    .replaceAll("\\s", "");
            byte[] der = Base64.decodeBase64(cleaned);
            PKCS8EncodedKeySpec spec = new PKCS8EncodedKeySpec(der);
            try {
                return KeyFactory.getInstance("RSA").generatePrivate(spec);
            } catch (Exception rsa) {
                return KeyFactory.getInstance("EC").generatePrivate(spec);
            }
        } catch (Exception e) {
            throw new IllegalStateException("Failed to parse private key PEM", e);
        }
    }
}

